function Eyebrow({children,center}){return <div style={{fontSize:".6rem",letterSpacing:".5em",color:GOLD,textTransform:"uppercase",marginBottom:20,display:"flex",alignItems:"center",gap:16,justifyContent:center?"center":"flex-start"}}><span style={{display:"block",width:32,height:1,background:GOLD}}/>{children}</div>;}
