function GoldBtn({children,onClick}){return <button onClick={onClick} style={{padding:"13px 32px",background:GOLD,color:BG,fontFamily:"'Rajdhani',sans-serif",fontWeight:700,fontSize:".85rem",letterSpacing:".18em",textTransform:"uppercase",border:"none",cursor:"none"}}>{children}</button>;}
function GhostBtn({children,onClick}){return <button onClick={onClick} style={{padding:"12px 32px",background:"transparent",color:GOLD,fontFamily:"'Rajdhani',sans-serif",fontWeight:700,fontSize:".85rem",letterSpacing:".18em",textTransform:"uppercase",border:`1px solid ${GOLD}`,cursor:"none"}}>{children}</button>;}


