//TEAM
function TeamPage({activeDept,setActiveDept}){
  const dept=DEPARTMENTS.find(d=>d.id===activeDept)||null;
  return(
    <div style={{position:"relative",zIndex:1,padding:"100px 8vw 80px",maxWidth:1400,margin:"0 auto"}}>
      <Eyebrow>05 — Team</Eyebrow>
      <div style={{display:"flex",flexWrap:"wrap",gap:8,marginBottom:48}}>
        <button onClick={()=>setActiveDept(null)} style={{padding:"10px 22px",fontFamily:"'Barlow Condensed',sans-serif",fontWeight:600,fontSize:".85rem",letterSpacing:".14em",textTransform:"uppercase",background:!activeDept?GOLD:"transparent",color:!activeDept?BG:MUTED,border:`1px solid ${!activeDept?GOLD:GOLD_DIM}`,cursor:"none",transition:"all .25s"}}>All Departments</button>
        {DEPARTMENTS.map(d=>(
          <button key={d.id} onClick={()=>setActiveDept(d.id)} style={{padding:"10px 22px",fontFamily:"'Barlow Condensed',sans-serif",fontWeight:600,fontSize:".85rem",letterSpacing:".14em",textTransform:"uppercase",background:activeDept===d.id?GOLD:"transparent",color:activeDept===d.id?BG:MUTED,border:`1px solid ${activeDept===d.id?GOLD:GOLD_DIM}`,cursor:"none",transition:"all .25s",display:"flex",alignItems:"center",gap:8}}>
            <span>{d.icon}</span>{d.name}
          </button>
        ))}
      </div>
      {dept&&(
        <div style={{border:`1px solid ${GOLD_DIM}`,padding:"36px 40px",background:"rgba(212,160,23,.03)",marginBottom:48,display:"flex",alignItems:"center",gap:32,flexWrap:"wrap"}}>
          <div style={{fontSize:"3.5rem"}}>{dept.icon}</div>
          <div style={{flex:1,minWidth:240}}>
            <div style={{fontSize:".58rem",letterSpacing:".5em",color:GOLD,textTransform:"uppercase",marginBottom:6}}>Department {String(dept.order).padStart(2,"0")}</div>
            <h2 style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"clamp(1.8rem,4vw,3rem)",letterSpacing:".06em",lineHeight:1,marginBottom:8}}>{dept.name}</h2>
            <p style={{fontSize:".82rem",color:MUTED,lineHeight:1.7,maxWidth:640}}>{dept.desc}</p>
          </div>
          <div style={{fontSize:".7rem",letterSpacing:".3em",color:MUTED,textTransform:"uppercase",textAlign:"center"}}>
            <div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"2.5rem",color:GOLD,lineHeight:1}}>{dept.members.length}</div>Members
          </div>
        </div>
      )}
      {(dept?[dept]:DEPARTMENTS).map((d)=>(
        <div key={d.id} style={{marginBottom:dept?0:64}}>
          {!dept&&(
            <div style={{display:"flex",alignItems:"center",gap:20,marginBottom:28,paddingBottom:16,borderBottom:`1px solid ${GOLD_DIM}`}}>
              <span style={{fontSize:"2rem"}}>{d.icon}</span>
              <div>
                <div style={{fontSize:".55rem",letterSpacing:".5em",color:GOLD,textTransform:"uppercase",marginBottom:4}}>Department {String(d.order).padStart(2,"0")}</div>
                <div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"1.6rem",letterSpacing:".06em"}}>{d.name}</div>
              </div>
              <div style={{marginLeft:"auto",fontSize:".6rem",letterSpacing:".3em",color:MUTED,textTransform:"uppercase",textAlign:"right"}}>
                <div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"1.8rem",color:GOLD,lineHeight:1}}>{d.members.length}</div>Members
              </div>
            </div>
          )}
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))",gap:16}}>
            {d.members.map((m,mi)=>(
              <div key={mi} style={{border:`1px solid ${GOLD_DIM}`,background:"rgba(255,255,255,.02)",overflow:"hidden",position:"relative"}}>
                <div style={{width:"100%",aspectRatio:"1/1",background:"linear-gradient(135deg,#0f0d08,#1c1808)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",position:"relative"}}>
                  {m.img?<img src={m.img} alt={m.name} style={{width:"100%",height:"100%",objectFit:"cover"}}/>:<>
                    <div style={{width:72,height:72,borderRadius:"50%",border:"2px dashed rgba(212,160,23,.3)",display:"flex",alignItems:"center",justifyContent:"center",marginBottom:10}}><span style={{fontSize:"1.6rem",opacity:.5}}>👤</span></div>
                    <span style={{fontSize:".55rem",letterSpacing:".3em",color:"rgba(212,160,23,.25)",textTransform:"uppercase"}}>Photo</span>
                  </>}
                  {mi===0&&<div style={{position:"absolute",top:10,right:10,padding:"3px 10px",background:GOLD,color:BG,fontSize:".5rem",letterSpacing:".3em",textTransform:"uppercase",fontWeight:700}}>Lead</div>}
                </div>
                <div style={{padding:"16px 18px"}}>
                  <div style={{fontFamily:"'Rajdhani',sans-serif",fontWeight:700,fontSize:"1rem",color:TEXT,marginBottom:4}}>{m.name}</div>
                  <div style={{fontSize:".6rem",letterSpacing:".3em",color:GOLD,textTransform:"uppercase"}}>{m.role}</div>
                  <div style={{fontSize:".6rem",letterSpacing:".25em",color:MUTED,textTransform:"uppercase",marginTop:4}}>{d.name}</div>
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}


